#include <stdio.h>
int main(){
    printf("A pointer is a variable that stores the memory address of another variable.\nExample in C:\nint x = 10;\nint *ptr = &x; // ptr holds address of x\nprintf(\"%d\", *ptr); // prints 10\n");
    return 0;
}

code.C++:
// COMPLETE, COMPILABLE C++ code
#include <iostream>
int main(){
    std::cout << "A pointer is a variable that stores the memory address of another variable." << std::endl;
    std::cout << "Example in C++:" << std::endl;
    std::cout << "int a = 5;" << std::endl;
    std::cout << "int *p = &a;" << std::endl;
    std::cout << "std::cout << *p; // prints 5" << std::endl;
    return 0;
}

