        System.out.println("Java does not expose raw pointers; object references act similarly.");
        System.out.println("Example (reference):");
        System.out.println("Integer obj = Integer.valueOf(10); // obj holds a reference to an Integer object");
        System.out.println("System.out.println(obj); // prints 10");
    }
}

